code:
PREFIX prov: <http://www.w3.org/ns/prov#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?p ?o ?pe ?po
        WHERE {
            # 1. Start with the properties of the target object
            <{obj_uri}> ?p ?o .

            # 2. Check if the object is a prov:Collection
            # This pattern only binds ?isCollection if <{obj_uri}> is a prov:Collection
            OPTIONAL {
                <{obj_uri}> rdf:type prov:Collection .
                BIND(TRUE AS ?isCollection)
            }

            OPTIONAL {
                FILTER (bound(?isCollection))
                <{obj_uri}> prov:hadMember ?member .
                ?member ?pe ?po .
            }
        }

example_usage:
PREFIX prov: <http://www.w3.org/ns/prov#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?p ?o ?pe ?po
        WHERE {
            # 1. Start with the properties of the target object
            <http://testwebsite/testProgram#AI_Task-information_extractor> ?p ?o .

            # 2. Check if the object is a prov:Collection
            # This pattern only binds ?isCollection if <http://testwebsite/testProgram#AI_Task-information_extractor> is a prov:Collection
            OPTIONAL {
                <http://testwebsite/testProgram#AI_Task-information_extractor> rdf:type prov:Collection .
                BIND(TRUE AS ?isCollection)
            }

            OPTIONAL {
                FILTER (bound(?isCollection))
                <http://testwebsite/testProgram#AI_Task-information_extractor> prov:hadMember ?member .
                ?member ?pe ?po .
            }
        }

